    11	
    12	var errNotMetricArtifact = fmt.Errorf("not a metric artifact")
    13	
    14	type Store struct {
    15		WorkingDir string
    16		execStore  *ddxexec.Store
    17	}
    18	
    19	func NewStore(workingDir string) *Store {
    20		return &Store{
    21			WorkingDir: workingDir,
    22			execStore:  ddxexec.NewStore(workingDir),
    23		}
    24	}
    25	
    26	// ListArtifacts returns all MET-* artifacts in document ID order.
    27	func (s *Store) ListArtifacts() ([]docgraph.Document, error) {
    28		graph, err := docgraph.BuildGraph(s.WorkingDir)
    29		if err != nil {
    30			return nil, err
    31		}
    32		ids := graph.All()
    33		out := make([]docgraph.Document, 0, len(ids))
    34		for _, id := range ids {
    35			if !strings.HasPrefix(id, "MET-") {
    36				continue
    37			}
    38			doc, ok := graph.Show(id)
    39			if !ok {
    40				continue
    41			}
    42			out = append(out, doc)
    43		}
    44		return out, nil
    45	}
